class Solution:
    def combinationSum(self, candidates: list[int], target: int) -> list[list[int]]:
        results = []

        def backtrack(current_combination, remaining_target, start_index):
            if remaining_target == 0:
                results.append(list(current_combination))
                return

            if remaining_target < 0:
                return

            for i in range(start_index, len(candidates)):
                num = candidates[i]
                current_combination.append(num)
                # Aynı sayıyı tekrar kullanabileceğimiz için 'i' değeri değişmez.
                # Ancak bir sonraki adayları ele alırken sıralı kombinasyonları garanti etmek için 'i' kullanırız.
                backtrack(current_combination, remaining_target - num, i)
                current_combination.pop()

        backtrack([], target, 0)
        return results
